def checkInclusion(s1, s2):
    if len(s1) > len(s2):
        return False

    s1_count = {}
    window = {}

    for c in s1:
        s1_count[c] = s1_count.get(c, 0) + 1

    for i in range(len(s2)):
        c = s2[i]
        window[c] = window.get(c, 0) + 1

        if i >= len(s1):
            left = s2[i - len(s1)]
            window[left] -= 1
            if window[left] == 0:
                del window[left]

        if window == s1_count:
            return True

    return False
